import React, { useState } from 'react';
import { Plus, Trash2, Save } from 'lucide-react';

const WorkoutLogger = ({ user }) => {
  const [workout, setWorkout] = useState({
    title: '',
    type: 'strength',
    intensity: 'medium',
    duration: 45,
    calories: '',
    notes: '',
    exercises: []
  });

  const [newExercise, setNewExercise] = useState({
    name: '',
    sets: 3,
    reps: 10,
    weight: 0
  });

  const workoutTypes = ['Strength', 'Cardio', 'HIIT', 'Yoga', 'Pilates', 'CrossFit', 'Running', 'Cycling'];
  const intensities = ['Low', 'Medium', 'High'];

  const handleAddExercise = () => {
    if (newExercise.name) {
      setWorkout({
        ...workout,
        exercises: [...workout.exercises, newExercise]
      });
      setNewExercise({ name: '', sets: 3, reps: 10, weight: 0 });
    }
  };

  const handleRemoveExercise = (index) => {
    const exercises = [...workout.exercises];
    exercises.splice(index, 1);
    setWorkout({ ...workout, exercises });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const calories = workout.calories || Math.round(workout.duration * (workout.type === 'cardio' ? 10 : workout.type === 'hiit' ? 12 : 6));
    alert(`Workout "${workout.title}" logged! You burned ~${calories} calories! 🔥`);
    console.log('Workout Data:', { ...workout, calories });
    setWorkout({
      title: '',
      type: 'strength',
      intensity: 'medium',
      duration: 45,
      calories: '',
      notes: '',
      exercises: []
    });
  };

  return (
    <div className="workout-logger">
      <h1 className="page-title">Log Workout</h1>

      <div className="logger-grid">
        {/* Form Card */}
        <div className="form-card">
          <h3 className="form-title">New Workout Session</h3>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Workout Title</label>
              <input
                type="text"
                className="form-input"
                placeholder="e.g., Morning Upper Body"
                value={workout.title}
                onChange={(e) => setWorkout({ ...workout, title: e.target.value })}
                required
              />
            </div>

            <div className="form-group">
              <label className="form-label">Workout Type</label>
              <select
                className="form-select"
                value={workout.type}
                onChange={(e) => setWorkout({ ...workout, type: e.target.value })}
              >
                {workoutTypes.map(type => (
                  <option key={type} value={type.toLowerCase()}>{type}</option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">Intensity</label>
              <select
                className="form-select"
                value={workout.intensity}
                onChange={(e) => setWorkout({ ...workout, intensity: e.target.value })}
              >
                {intensities.map(int => (
                  <option key={int} value={int.toLowerCase()}>{int}</option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">Duration (minutes)</label>
              <input
                type="number"
                className="form-input"
                value={workout.duration}
                onChange={(e) => setWorkout({ ...workout, duration: parseInt(e.target.value) })}
                required
              />
            </div>

            <div className="form-group">
              <label className="form-label">Calories Burned (optional)</label>
              <input
                type="number"
                className="form-input"
                placeholder="Auto-calculated if empty"
                value={workout.calories}
                onChange={(e) => setWorkout({ ...workout, calories: e.target.value })}
              />
            </div>

            <div className="form-group">
              <label className="form-label">Notes</label>
              <textarea
                className="form-input"
                rows="3"
                placeholder="How did you feel? Any PRs?"
                value={workout.notes}
                onChange={(e) => setWorkout({ ...workout, notes: e.target.value })}
              />
            </div>

            <button type="submit" className="btn-primary">
              <Save size={18} style={{ marginRight: '8px' }} />
              Save Workout
            </button>
          </form>
        </div>

        {/* Exercise List Card */}
        <div className="form-card">
          <h3 className="form-title">Add Exercises</h3>
          <div className="form-group">
            <div style={{ display: 'flex', gap: '10px' }}>
              <input
                type="text"
                className="form-input"
                placeholder="Exercise name"
                value={newExercise.name}
                onChange={(e) => setNewExercise({ ...newExercise, name: e.target.value })}
                style={{ flex: 2 }}
              />
              <input
                type="number"
                className="form-input"
                placeholder="Sets"
                value={newExercise.sets}
                onChange={(e) => setNewExercise({ ...newExercise, sets: parseInt(e.target.value) })}
                style={{ flex: 1 }}
              />
            </div>
            <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
              <input
                type="number"
                className="form-input"
                placeholder="Reps"
                value={newExercise.reps}
                onChange={(e) => setNewExercise({ ...newExercise, reps: parseInt(e.target.value) })}
                style={{ flex: 1 }}
              />
              <input
                type="number"
                className="form-input"
                placeholder="Weight (kg)"
                value={newExercise.weight}
                onChange={(e) => setNewExercise({ ...newExercise, weight: parseInt(e.target.value) })}
                style={{ flex: 1 }}
              />
              <button className="btn-primary" onClick={handleAddExercise} style={{ width: 'auto', marginTop: 0 }}>
                <Plus size={18} />
              </button>
            </div>
          </div>

          <div className="exercise-list">
            {workout.exercises.length === 0 ? (
              <p style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '20px' }}>
                No exercises added yet
              </p>
            ) : (
              workout.exercises.map((ex, index) => (
                <div className="exercise-item" key={index}>
                  <div>
                    <div className="exercise-name">{ex.name}</div>
                    <div className="exercise-meta">
                      {ex.sets} sets × {ex.reps} reps @ {ex.weight}kg
                    </div>
                  </div>
                  <button 
                    onClick={() => handleRemoveExercise(index)}
                    style={{ background: 'transparent', color: 'var(--danger)' }}
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default WorkoutLogger;
